def get_median(arr1, arr2, size):
    merged = []
    i = j = 0
    while i < size and j < size:
        if arr1[i] <= arr2[j]:
            merged.append(arr1[i])
            i += 1
        else:
            merged.append(arr2[j])
            j += 1
    while i < size:
        merged.append(arr1[i])
        i += 1
    while j < size:
        merged.append(arr2[j])
        j += 1
    mid = len(merged) // 2
    if len(merged) % 2 == 0:
        return (merged[mid - 1] + merged[mid]) / 2
    else:
        return merged[mid]

