def rgb_to_hsv(r, g, b):
    r /= 255.0
    g /= 255.0
    b /= 255.0

    max_color = max(r, g, b)
    min_color = min(r, g, b)
    diff = max_color - min_color

    if max_color == min_color:
        h = 0.0
    elif max_color == r:
        h = (60 * ((g - b) / diff) + 360) % 360
    elif max_color == g:
        h = (60 * ((b - r) / diff) + 120) % 360
    else:
        h = (60 * ((r - g) / diff) + 240) % 360

    if max_color == 0.0:
        s = 0.0
    else:
        s = (diff / max_color) * 100

    v = max_color * 100

    return h, s, v

