def mul_even_odd(arr):
    evn = -1
    odd = -1
    for i in range(len(arr)):
        if arr[i] % 2 == 0:
            if evn == -1:
                evn = arr[i]
        else:
            if odd == -1:
                odd = arr[i]
        if evn != -1 and odd != -1:
            break
    return evn * odd

def right_insertion(nums, x):
    l, r = 0, len(nums)
    while l < r:
        m = (l + r) // 2
        if nums[m] <= x:
            l = m + 1
        else:
            r = m
    return l

